function pinStyle(index: number, hoveredPinIndex?: number | null) {
    return {
        transformBox: 'fill-box' as const,
        transformOrigin: 'center',
        transform: hoveredPinIndex === index ? 'scale(1.12)' : 'scale(1)',
        transition: 'transform 0.2s ease-out',
    }
}

